using System;
using System.Collections.Generic;
using System.Reflection;

public class DIContainer
{
    private readonly Dictionary<Type, Type> _registrations = new();

    public void Register<TInterface, TImplementation>() where TImplementation : TInterface
    {
        _registrations[typeof(TInterface)] = typeof(TImplementation);
    }

    public object Resolve(Type type)
    {
        if (!_registrations.TryGetValue(type, out var implementationType))
        {
            throw new InvalidOperationException($"No registration found for {type}");
        }

        var constructor = implementationType.GetConstructors().FirstOrDefault();
        if (constructor == null)
        {
            throw new InvalidOperationException($"No constructor found for {implementationType}");
        }

        var parameters = constructor.GetParameters();
        var resolvedParameters = new object[parameters.Length];

        for (int i = 0; i < parameters.Length; i++)
        {
            resolvedParameters[i] = Resolve(parameters[i].ParameterType);
        }

        return constructor.Invoke(resolvedParameters);
    }

    public T Resolve<T>()
    {
        return (T)Resolve(typeof(T));
    }
}
